var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"문주님. 몰래 보물을 훔쳐가려던 녀석을 잡아왔습니다.","JPN":"門主。こっそり宝物を盗もうとしたやつを捕まえてきました。","ENG":"Sir, I caught the rat that was attempting to steal our treasure.","TWN":"掌門人，抓到偷寶物的人了。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"윽…!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃…！"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L5_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"흑동의 경비를 뚫고 창고까지 들어가다니. 어린 것이 제법이구나.","JPN":"黒東の警備をくぐり抜けて倉庫まで入るとは。なかなかであるな。","ENG":"I'm impressed you made it past Black East's guards and into our storage, child.","TWN":"竟然可以突破黑東的戒備闖到倉庫裡，小丫頭蠻厲害的嘛。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"제자여, 이 도둑을 어쩌면 좋겠느냐?","JPN":"弟子よ、この泥棒をどうすべきか？","ENG":"Flora, what should I do with this thief?","TWN":"徒弟，你說該拿這小偷怎麼辦才好？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"화천의 규율대로라면 보물을 훔치려 한 죄인은 두 팔을 자르고 추방하는 것이 옳습니다.","JPN":"華天の規律どおりだと、宝物を盗もうとした罪人は両腕を切り、追放すべきです。","ENG":"According to the laws of Huatian, all thieves are to have their arms cut off and exiled.","TWN":"按照華天的規矩，盜取寶物的犯人必須砍斷雙臂後逐出華天。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"흐음- 그렇지.","JPN":"ふむ、そうだろうな。","ENG":"Hmm... That is true.","TWN":"嗯嗯，沒錯。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"아가. 네가 가져가려던 것은 우리 문파의 보물이다.","JPN":"幼子。お前が持ち出そうとしたものは、我々門派の宝物だ。","ENG":"Child. What you were trying to steal was our sect's treasure.","TWN":"小丫頭，你偷的東西是我們門派的寶物。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"서민에겐 아무 의미도 없는 물건일 텐데, 왜 가지려 했지?","JPN":"庶民には何の意味もないものであるはずだが、どうして持って行こうとした？","ENG":"To you, it has no meaning. So what were your intentions?","TWN":"對市井小民來說應該沒什麼意義，你為何要偷呢？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"무기… 몰래 가져오면… 먹으꺼… 준댔어.","JPN":"武器……こっそり持ってくると……食べ物……くれるって。","ENG":"If I... take the weapon... they said... they'd feed me.","TWN":"他說…只要把武器偷給他…就給我…吃的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"허허, 먹을 것이라.","JPN":"ほほう、食べ物か。","ENG":"Ha ha... Was it for food?","TWN":"呵呵，原來是要吃的。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"누군가의 사주를 받았군요. 심문해서 알아보겠습니다.","JPN":"誰かにそそのかされましたね。尋問して調べてみます。","ENG":"Someone ordered her to steal it. I shall question her further.","TWN":"看來她是受人指使，讓我來拷問她。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"크르르……!","JPN":"ガルル……！","ENG":"Grr...!","TWN":"呸……！"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_11"},{"id":"L20_1","type":"dialog","speaker":"MEMBER_CLAN_NULL_NULL","text":{"KOREA":"이 녀석! 감히 누구에게 이빨을 들이미느냐!","JPN":"この野郎！　誰に歯向かっているのか！","ENG":"Filthy girl! How dare you snarl at our master?!","TWN":"臭丫頭！好大膽子！竟敢對掌門人不敬！"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"됐다. 어디 그럴 만한 자들이 한 둘이더냐?","JPN":"止せ。そのような者はどこにでもいる。","ENG":"Enough. She is one of many who would.","TWN":"好了，她也不是唯一一個對我不敬的人。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"그건 그렇고, 아가.","JPN":"それはさておき、幼子よ。","ENG":"Nevertheless, child.","TWN":"丫頭，我問你，"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"우리 문파에 문하생으로 들어오지 않겠니?","JPN":"我々の門派に門下生として入らぬか？","ENG":"Would you like to join our sect as a disciple?","TWN":"你要入我們門派成為門生嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"무나생…?","JPN":"もんかせー……？","ENG":"\\"deesaipal...?\\"","TWN":"門生…？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"장문인.","JPN":"掌門人。","ENG":"Master.","TWN":"掌門人。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"보물을 훔치려 한 죄인입니다. 어리다고 해서 화천의 법에 예외를 둘 순 없지 않습니까?","JPN":"宝物を盗もうとした罪人です。幼いという理由で、華天の法に例外を作るわけにはいきません。","ENG":"She is a sinner and a thief. We cannot let her be an exception to the laws of Huatian.","TWN":"她可是偷寶物的犯人，怎麼可以因為她年紀小，就排除在華天規矩之外呢？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"그렇다고 저런 실력이 좋은 싹을 그냥 잘라버리긴 아깝지 않느냐?","JPN":"だからといって、あのような実力のある芽を切ってしまうことはもったいないではないか。","ENG":"Then again, is it not a shame to waste such talent?","TWN":"話雖如此，但就這樣失去一個人才，不覺得可惜嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KAUMA_CLAN_NULL_NULL","text":{"KOREA":"그건 그렇습니다만…","JPN":"それはそうですが……","ENG":"Yes, it is a shame, but–","TWN":"話是沒錯…"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"잘잘못을 깨우치게 하려면, 우선 무엇이 옳고 그른 지부터 가르치는 것이 공정한 처사지.","JPN":"良し悪しを教えるためには、まずはどれが正しく、どれが間違いなのかを教えるのが公正なやり方だ。","ENG":"In order for her to realize her mistake, it is only fair that she learns right from wrong first.","TWN":"要想讓她能夠分辨是非對錯，就要先教她什麼是對的，什麼是錯的，這樣才對不是嗎？"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KAUMA_CLAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FATHER_CLAN_BLACK_NULL","text":{"KOREA":"어떠냐? 도둑질을 그만두고 내 제자가 되면 먹을 것도 주마.","JPN":"どうだ？　泥棒をやめて私の弟子になれば食べ物も与えよう。","ENG":"What do you say? Stop stealing and become my pupil, and then I shall give you something to eat.","TWN":"你說呢？你不當小偷，改當我的徒弟的話，我還會給你東西吃喔。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_CHILD","text":{"KOREA":"배울래.","JPN":"教わる。","ENG":"I want to learn.","TWN":"好。"},"stage":{"bg":"CLAN","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"시엘…?","JPN":"シエルちゃん……？","ENG":"Ciel...?","TWN":"希爾…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"…시엘!","JPN":"……シエルちゃん！","ENG":"...Ciel!","TWN":"…希爾！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"으음…","JPN":"うむ……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"수업 벌써 끝났어.","JPN":"もう授業終わったよ。","ENG":"Class is already over.","TWN":"下課了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"정말- 또 자고 있던 거야?","JPN":"もうーまた寝てたの？","ENG":"Seriously, did you doze off again?","TWN":"真是的，你又睡著了嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"미안하오. 낮에 깨어 있는 건 역시 곤혹스럽구려.","JPN":"申し訳ありません。昼間に起きていることは、やはり困難ですね。","ENG":"My apologies. It is still difficult for me to stay awake during the day.","TWN":"抱歉，在下真的不太適應白天醒著。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어디 건강에 이상이 있는 건 아니지? 역시 병원을 가보는 편이 좋지 않을까?","JPN":"体のどこかが悪いわけじゃないよね？　やっぱり病院に行った方がいいんじゃない？","ENG":"Are you sick? Shouldn't you go see a doctor or something?","TWN":"你是不是身體哪裡有問題？要不要去看個醫生？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"괜찮소. 이렇게 해가 질 무렵에는 정신이 맑아진다오.","JPN":"大丈夫です。日が沈む頃には、頭がすっきりします。","ENG":"I am in adequate health. My mind becomes clearer as the sun goes down.","TWN":"沒事，像現在太陽下山後，在下就會恢復精神。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"미카도 걱정이 쓸데없이 많네. 열등생답게 수업이 지루해서 졸고 있었을 뿐이겠지. 안 그래?","JPN":"ミカは余計なことを心配しすぎだね。劣等生だから授業がつまらなくてうとうとしてただけよ。違う？","ENG":"You worry too much, Mika. She just sleeps during class because she finds it boring, like the other losers. Isn't that right?","TWN":"米卡會不會擔心太多，她就是劣等生，劣等生上課打瞌睡也是正常發揮吧？難道不是嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그렇지 않아! 시엘도 바뀌려고 얼마나 노력하고 있는데!","JPN":"そんなことないよ！　シエルちゃんも変わるために頑張ってるんだから！","ENG":"That's not true! Ciel's trying really hard to change!","TWN":"才不是！希爾也很努力要改變！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"밤마다 내 비장의 최면술 자장가까지 불러줬는데도 수면 패턴이 바뀌지 않았다는 건 정말 큰일이라고!","JPN":"毎晩私のとっておきの催眠術子守歌まで歌ってあげたのに、睡眠パターンが変わらないのは本当に変なんだって！","ENG":"I even sing her my hypnotizing lullaby every night, and her sleep pattern still won't change! It's a serious issue!","TWN":"我每晚都唱催眠搖籃曲給她聽，但還是無法改變她的睡眠習慣，這很嚴重欸！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그게 노래였던 거요?","JPN":"あれが歌だったのですか？","ENG":"Was that supposed to be a song?","TWN":"原來那是首歌嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"푸핫…!","JPN":"ぶはっ……！","ENG":"Ahaha...!","TWN":"噗哧…！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"흐잉, 시엘-! 네가 그렇게 말하면 어떡해!","JPN":"ふえん、シエルちゃーん！　あなたがそんなこと言っちゃダメでしょ！","ENG":"Hngh... Ciel! How can you say that!?","TWN":"嗚嗚，希爾！你怎麼可以拆我的台！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"PLAYERS_NPC_ACADEMY_NULL","text":{"KOREA":"어엇! 공이 학교 밖으로 튀어나갔다!","JPN":"あれ！　ボールが学校の外に出ちゃったぞ！","ENG":"No! The ball went over the school fence!","TWN":"喂！球飛到校外了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"멍-!","JPN":"ワンッ！","ENG":"Woof!","TWN":"汪汪！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_07"},{"id":"L9_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어라? 알렉산더? 언제부터 저기에 있었지?","JPN":"あれ？　アレクサンダー？　いつからあそこにいたんだろう？","ENG":"Huh? Alexander? Since when was he there?","TWN":"嗯？亞歷山大？你怎麼會跑到那裡？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아앗, 알렉산더가 공을 쫓아서 도로로 뛰쳐나갔어요!","JPN":"ああっ、アレクサンダーがボールを追いかけて道路に飛び出ました！","ENG":"Oh, no! Alexander's chasing the ball into the middle of the street!","TWN":"糟糕，亞歷山大追球追到馬路上了！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"…트럭이야! 위험해!","JPN":"……トラック！　危ない！","ENG":"A truck's coming! Watch out!!","TWN":"…有卡車！危險！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRIVER_NPC_ACADEMY_NULL","text":{"KOREA":"음? 잘못 본 건가?","JPN":"うん？　見間違いか？","ENG":"Hmm? Was I hallucinating?","TWN":"嗯？我眼花嗎？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRIVER_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRIVER_NPC_ACADEMY_NULL","text":{"KOREA":"방금 전까지 바로 앞에 개 한 마리가 있었던 것 같은데?","JPN":"さっきまで目の前に犬がいたような気がしたけど？","ENG":"I'm certain there was a dog right in front of me...","TWN":"剛才正前方不是有一隻狗嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRIVER_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"헥- 헥-","JPN":"ヘッ、ヘッ！","ENG":"*Pant* *Pant*","TWN":"哈哈，哈哈。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_02"},{"id":"L23_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"방금은 위험했소.","JPN":"先ほどは危なかったです。","ENG":"A close call, that was.","TWN":"剛才好危險。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"목표물을 쫓을 때에도 언제나 주변을 경계하도록 하시오, 강아지 도령.","JPN":"標的を追いかける時でも常に周りに警戒してください、犬殿。","ENG":"Always be aware of your surroundings when chasing after your target, young puppy.","TWN":"追目標的同時也要觀察周圍的情況，狗少爺。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"멍! 멍!","JPN":"ワン！　ワン！","ENG":"Woof! Woof!","TWN":"汪！汪！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_03"},{"id":"L28_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"알렉산더! 괜찮은가!","JPN":"アレクサンダー！　大丈夫か！","ENG":"Alexander! Are you okay?!","TWN":"亞歷山大！你沒事吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"와아! 시엘 언니가 알렉산더를 구해주셨군요!","JPN":"わあっ！　シエルさんがアレクサンダーを助けてくれたんですね！","ENG":"Wow! Ciel just saved Alexander!","TWN":"哇！是希爾姊姊救了亞歷山大！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"멍-!","JPN":"ワンッ！","ENG":"Woof!","TWN":"汪！汪！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_08"},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오오, 방금 봤어? 시엘이 순식간에 뛰어내려서 강아지를 구해내는 거?","JPN":"おお、今の見た？　シエルちゃんが一瞬で飛び降りて、犬を救ったよ！","ENG":"Whoa, did you see that? Ciel just ran straight into traffic to save the puppy.","TWN":"哇喔，你有看到嗎？希爾剛才瞬間就衝出去救了小狗欸？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 내가 구할 수도 있었어.","JPN":"フン、私が救うこともできたの。","ENG":"Hmph. I could've saved him too.","TWN":"哼，我也可以啊。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"녀석이 먼저 나서길래, 굳이 나서지 않았을 뿐이라고.","JPN":"あいつが先に出たから、私が出る必要性を感じなかっただけ。","ENG":"But I saw her go after him first, so I didn't see the need to.","TWN":"是因為她先衝出去，我才沒衝的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"흐음-","JPN":"ふーん。","ENG":"Hmm...","TWN":"嗯哼。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘, 너 시엘을 엄청 경계하는구나? 혹시 경쟁의식이라도 갖고 있는 건 아니지?","JPN":"ナイエル、あなたシエルちゃんのことをめっちゃ警戒してない？　もしかして、競争意識でも持ってるの？","ENG":"Naielle, you seem to be very self-conscious of Ciel. Do you see her as your rival or something?","TWN":"奈爾，你很在意希爾喔？你該不會把她當成假想敵吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무… 무어어어?! 내가 그럴 리가 없잖아?","JPN":"は……はあああ！？　私がそんなわけないでしょ？","ENG":"W-w-what?! I would never!","TWN":"什…什麼？！我才沒有咧！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"저 녀석이 아무리 날뛰어봐야 결국 이 엘리트님과의 훈련대결에서 진 하수일 뿐이거든!","JPN":"あいつが目立った行動をしたところで、結局はこのエリート様との訓練対決で負けた敗者なだけ！","ENG":"It doesn't matter how much she tries! She'll always be one step behind me!","TWN":"她跑得再快，也是在訓練中輸給我的手下敗將。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"PLAYERS_NPC_ACADEMY_NULL","text":{"KOREA":"다들 봤어? 절체절명의 순간에 뛰어들어 강아지를 구하는 저 모습!","JPN":"みんな、見たか？　絶体絶命の瞬間に飛び込んで、犬を救うあの姿！","ENG":"Did you see that? She saved that puppy by jumping in front of the truck just as it was about to crash!","TWN":"你們有看到嗎？在緊要關頭飛奔去救狗狗的帥樣！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PLAYERS_NPC_ACADEMY_NULL","text":{"KOREA":"방금 정말로 멋졌다고, 신입생!","JPN":"さっきの姿、本当にカッコよかったぞ、新入生！","ENG":"That was really cool, new kid!","TWN":"你剛才真的超帥的，新生！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PLAYERS_NPC_ACADEMY_NULL","text":{"KOREA":"저 정도 순발력이면 총알을 막아냈다는 얘기도 분명 사실일 거야!","JPN":"あの瞬発力なら、銃弾を止めたって話もきっと本当だろう！","ENG":"With those reflexes, it must be true that she can block bullets!","TWN":"有那樣的瞬間爆發力，可以擋子彈的事應該是真的吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"VOLLEYHEAD_NPC_ACADEMY_NULL","text":{"KOREA":"질주하는 트럭 앞에서도 굴하지 않는 정의감! 피구의 열정에 어울리는 불꽃이로군!","JPN":"疾走するトラックの前でも屈しない正義感！　ドッジボールの熱情にぴったりだな！","ENG":"Her courage to jump in front of a rushing truck! Like dodgeball, her passion is blazing hot!","TWN":"在高速疾駛的卡車面前也毫不退縮的正義感！這份熱情很適合躲避球呢！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"VOLLEYHEAD_NPC_ACADEMY_NULL","text":{"KOREA":"피구에 재능이 없어도 상관없다! 우리가 책임지고 가르쳐줄 테니 피구부에 들어오지 않겠나!","JPN":"ドッジボールの才能がなくても構わない！　俺たちが責任を持って教えてやるから、ドッジボール部に入らないか！","ENG":"It doesn't matter if you don't have a knack for dodgeball! We'll teach you! Come join our club!","TWN":"沒有打躲避球的天分也無所謂！我們會負責教你，你願意來躲避球社嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본관도 동물의 위기를 외면하지 않는 시엘 언니의 마음에 감격했다!","JPN":"本官も動物の危機から目を背けないシエルの心に感動した！","ENG":"Ciel's determination to save an endangered animal moved me as well!","TWN":"本官也很感激希爾姊姊沒有對小動物見死不救！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"한 발 늦었지만, 부디 우리 애니멀 레스큐 포스의 대원이 되어주지 않겠나!","JPN":"ひと足遅くなったが、どうか我々アニマルレスキューフォースの隊員になってくれないか！","ENG":"It may be too late, but will you please become a member of the Animal Rescue Specialists?","TWN":"雖然晚了一步，但請你務必要成為我們A.R.S的隊員好嗎！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"뜻밖의 제안들이라 당황스럽구려.","JPN":"予想外の提案ですので、困りましたね。","ENG":"The abundance of unexpected offers leaves me perplexed.","TWN":"突然收到這麼多邀請，在下有點不知所措。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이렇게 간단히 본인을 그대들의 일원으로 받아들여도 정말 괜찮은 거요?","JPN":"このように簡単に自分を貴殿らの一員として受け入れても、本当に大丈夫なのですか？","ENG":"Are you sure you wish to take me in as a member of your club?","TWN":"這麼輕易就接受在下成為隊員真的沒關係嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그럼 물론이지!","JPN":"それはもちろんだよ！","ENG":"Of course!","TWN":"那當然！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어그로랑 블로킹이 변두리에서 위험에 처했을 때도, 학생회 못지 않게 활약했다면서?","JPN":"アグロとブロッキングが街外れで危ないことになっていた時も、活躍してくれたんだってね？","ENG":"I heard you helped out as much as the Student Council when Aggro and Block were in danger on the outskirts, right?","TWN":"我聽說阿格洛和布洛京在校外遇到危險時，你的功勞也不亞於學生會？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"첫 만남이 조금 삐걱거렸던 건 사실이지만… 시엘이 행동으로 보여준 선의는 모두의 마음에 와닿았을 거야!","JPN":"第一印象がギクシャクしたのは事実だけど……シエルが行動として見せてくれた善意は、みんなの心に響いたはずだよ！","ENG":"Although we started off on the wrong foot... seeing your altruistic nature in action has warmed everyone's heart!","TWN":"第一次見面時是有點尷尬…不過希爾你透過行動表達出來的好意，相信大家都有感受到的！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"..."},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"저 녀석, 평소엔 잠만 자면서 해가 지고 나면 엄청 쌩쌩해지네.","JPN":"あいつ、普段は寝てばっかのくせに、日が沈むとめちゃくちゃピンピンしてるね。","ENG":"Sheesh. She sleeps all day, and she's wide awake after the sun goes down.","TWN":"那傢伙白天光顧著睡覺，太陽下山後倒是很有活力嘛。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"설마… 낮에 자고 밤에 일어나는 게 힘의 비결인가?","JPN":"まさか……昼に寝て夜に起きるのが力の秘密？","ENG":"Could the secret to her powers be sleeping in the morning and waking up at night?","TWN":"難道…她的秘訣就是白天睡覺，晚上起床？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다행이다.","JPN":"よかった。","ENG":"Thank goodness.","TWN":"太好了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐가-?","JPN":"何が～？","ENG":"About what?","TWN":"好什麼？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"처음엔 시엘이 학교생활에 적응을 못 할까 걱정했는데, 이젠 다들 시엘에게 먼저 다가가고 있잖아요?","JPN":"最初はシエルちゃんが学校生活に適応できないんじゃないかって心配してたんですけど、今はみんなの方からシエルちゃんのところに集まってきてるじゃないですか。","ENG":"I was worried that Ciel might not adjust to her new school life. But now, everyone's approaching her first!","TWN":"我一開始還很擔心希爾無法適應學校生活，現在大家都願意主動向希爾伸出手呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으응- 시엘은 겉은 차갑고 딱딱해 보이지만, 실제론 섬세하고 친절한 사람이니까-","JPN":"うーん、シエルはいっけん冷たくて堅く見えるけど、本当は繊細で優しい人だからねぇ～","ENG":"Mhmm... Ciel may look hard and cold on the outside, but she's a kind and delicate person.","TWN":"嗯嗯，希爾雖然外表看起來很高冷，但其實是一個很貼心又親切的人。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"얼마 전에 위성 안테나를 설치할 때도 도와주고, 낮잠도 같이 자고- 이번 주말엔 TRPG도 다 같이 하기로 약속했는걸-?","JPN":"こないだ衛星アンテナを設置したときにも助けてくれたし、一緒に昼寝もしてるし～今週末にはみんなでTRPGやろうって約束したんだよ～？","ENG":"She even helped me install the satellite antenna a few days ago. We took naps together... and we also plan on playing a TRPG on the weekends.","TWN":"我之前在裝衛星天線時她也有幫忙，而且我們白天還一起打瞌睡，下次也約好要一起去玩TRPG欸。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗! 그거 던전 앤 카운터즈 말하는 거죠? 저도 같이 껴도 돼요?","JPN":"あっ！　それ、ダンジョン&カウンターズのことでしょ？　私も混ざっていいですか？","ENG":"Oh! You mean \\"Dungeon and Counters?\\" Could I join too?","TWN":"喔！你是說那個龍與制裁者對吧？我可以+1嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…쳇-","JPN":"……ちっ。","ENG":"...Tch!","TWN":"…嘖。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};